# Let me also verify with a small direct brute force on a tiny case
# to make sure the approach is correct

# Test: count triples (a,b,c) with a,b,c <= 3^2=9 and 3^3=27 | a^3+b^3+c^3
small_N_MAX = 3**2  # 9
small_MOD = 3**3   # 27

small_N_direct = 0
for a in range(1, small_N_MAX + 1):
    for b in range(1, small_N_MAX + 1):
        for c in range(1, small_N_MAX + 1):
            if (a**3 + b**3 + c**3) % small_MOD == 0:
                small_N_direct += 1

print(f"Direct count (small): {small_N_direct}")

# Now using our method
small_cubes = [a**3 % small_MOD for a in range(1, small_N_MAX + 1)]
small_freq = Counter(small_cubes)
small_pair_freq = Counter()
for r1, cnt1 in small_freq.items():
    for r2, cnt2 in small_freq.items():
        small_pair_freq[(r1 + r2) % small_MOD] += cnt1 * cnt2

small_N_method = 0
for r_pair, cnt_pair in small_pair_freq.items():
    needed = (-r_pair) % small_MOD
    if needed in small_freq:
        small_N_method += cnt_pair * small_freq[needed]

print(f"Method count (small): {small_N_method}")
print(f"Match: {small_N_direct == small_N_method}")

